/* ============================================================
   Empire State Trail — shared core: data + reusable app controller.
   All three design-system apps load this; only their CSS differs.
   ============================================================ */
const TOTAL = ROUTE[ROUTE.length-1][2];

/* ---- the Shoreline Trail: imported, not adopted -----------------------------
   Somebody's GPX off RideWithGPS — Buffalo's Outer Harbor up the Niagara to
   Youngstown by way of the West River path on Grand Island. It is drawn and
   nothing else. Trail miles are what make a line part of this app's arithmetic:
   give it mileposts and it starts turning up in Nearby, in the day planner and in
   every distance quoted, off a stranger's track nobody has checked against the
   ground. So the geometry lands now and the mileage decision waits.
   The file in gpx/ is the line — it is parsed at the moment the layer is first
   switched on rather than pasted into this file as a second copy that can drift,
   and its length is measured from those same points rather than quoted. */
const SHORE={
  name:'Shoreline Trail',
  sub:'Buffalo \u2192 Youngstown, via the West River path',
  file:'gpx/Total_Shoreline_Trail_via_West_River.gpx',
  src:'https://ridewithgps.com/routes/38214982',
  srcName:'RideWithGPS',
  drawn:'2021-12-20',           // the GPX's own stamp, not the day it was imported
  color:'#6b3fa0'
};

// The trail's own home page, which is also where the official GPX for a GPS unit
// lives — the layers control links to it the same way the borrowed layers link to
// theirs, because "where did this line come from" is the same question either way.
const EST_SRC='https://empiretrail.ny.gov/import-instructions';
/* The blue dot every phone map uses for "you". Simulated or off the GPS, it means
   the same thing and so it looks the same — the dark accent it used to wear read as
   one more piece of trail furniture. It rides in a pane of its own above the markers
   so nothing can cover it: not a road line, not forty lodging pins, not a milepost.
   Below the popup pane, though — a popup you cannot read is worse. */
const ME_BLUE='#1a73e8', ME_PANE='mePane';
/* Past this far from the route you are not on the trail, you are planning a trip to
   it. Generous on purpose: a rider detouring to a motel, a diner or an airport is
   still riding this trail, and only a genuinely different-state fix should trip it. */
const OFF_TRAIL_MI=60;
// Zoom at which pins start showing their names beside them.
const POI_LABEL_Z=13;
/* Above every pane Leaflet ships (popups are the highest at 700) and every pane the
   layer registry makes at 600, so a hovered pin is never behind anything. */
const HI_PANE_Z='1200';
// Beats any z-index Leaflet derives from a marker's y position within the same pane.
const HI_Z_OFFSET=100000;
// How far the NWS hourly grid actually runs, and therefore how many days we show.
const WX_MAX_DAYS=6;
// The town outlook fetches a forecast per town, so it caps how many one tap will pull
// and how far out it trusts the hourly grid — arrivals past this simply have no data.
const WX_MAX_TOWNS=14;
const WX_HORIZON_MS=6.3*24*36e5;

/* ---- NYSDOT traffic counts -------------------------------------------------
   The AADT layer behind the state's Traffic Data Viewer: annual average daily
   traffic, which is the number that answers the question a rider actually has
   about a road — how much of it will be going past me. Off by default and drawn
   only from close in, because a square mile of Syracuse holds about a thousand
   of these segments and half a megabyte a pan is worse than no layer at all. */
const AADT_URL='https://gis.dot.ny.gov/hostingny/rest/services/Roadways/Traffic_Monitoring/FeatureServer/1/query';
const AADT_SRC='https://www.dot.ny.gov/tdv';
const AADT_MINZ=10, AADT_CAP=400;
/* Google as a basemap, through the Maps JS API rather than tile URLs.
   Pulling mt*.google.com into an L.tileLayer is the answer every search result gives
   and it is the wrong one twice over: the Maps Platform terms forbid Google content
   under a non-Google map, and those tiles never carry the key, so none of the console
   restrictions below apply to them. GoogleMutant runs a real Google map underneath
   Leaflet's panes instead, which keeps Google's logo, attribution and terms link on
   screen where the licence expects them.

   The key rides in a meta tag in index.html. A browser key cannot be secret — it is
   fetched by the page, so anyone can read it — and Google's answer is restriction,
   not concealment: an HTTP-referrer allowlist plus Maps JavaScript API only plus a
   quota cap makes a copied key useless elsewhere and uncapped billing impossible.
   Rotating it is a one-line edit in the shell, not a hunt through this file.

   Nothing here loads until someone actually picks a Google layer. Dynamic Maps bills
   per map load, so a rider who never leaves OSM should never cost anything, and the
   app should not be waiting on Google's bootstrap to finish on a trailside bar of
   signal before it can draw a map at all. */
const GMAPS_SRC='https://maps.googleapis.com/maps/api/js?v=weekly&loading=async';
const GMUTANT_SRC='https://unpkg.com/leaflet.gridlayer.googlemutant@0.16.0/dist/Leaflet.GoogleMutant.js';
const GMAPS_CB='__estGmapsReady';
const GMAPS_LS='est-gmaps-key';
/* Two places, in this order, and the order is the whole point. A restricted production
   key belongs in the shell where every visitor gets it. A demo key — the throwaway one
   Google hands out for prototyping — belongs in localStorage on one machine, because it
   lives outside any Cloud project and so cannot be given a referrer allowlist, an API
   restriction or a quota cap. An unrestrictable key in a public repo is a live credential
   with nothing standing behind it, so it stays out of the commit:
     localStorage.setItem('est-gmaps-key','AIza…')   // this browser only, never shipped */
function gmapsKey(){
  try{ const k=(localStorage.getItem(GMAPS_LS)||'').trim(); if(k) return k; }catch(e){}
  const m=document.querySelector('meta[name="google-maps-key"]');
  return m ? (m.content||'').trim() : '';
}
/* Road-snapping for the measure tool. FOSSGIS's public OSRM (bike profile) both snaps a
   dropped point to the nearest way (/nearest) and traces the roads between two points
   (/route), so a traced leg reads real pedalled miles rather than straight-line. A point
   further than MEASURE_SNAP_M metres from any way is treated as off-road and left where it
   fell — the tolerance that stops a spot out in a field from yanking onto a road it has
   nothing to do with. Every call degrades to a straight great-circle hop when it fails or
   you're offline, so the tool still works with no network, just without the snap. */
const OSRM_BASE='https://routing.openstreetmap.de/routed-bike';
const MEASURE_SNAP_M=40;
/* Bands as a bike feels them, not as a traffic engineer files them: five hundred
   vehicles a day is where a road stops being empty, and fifteen hundred is where
   most riders would rather be somewhere else. Everything above that is one colour,
   because past the point you would avoid it, how much worse it gets is somebody
   else's question. Weights run heavier than the route line — a hairline you have
   to hunt for cannot answer "which way round do I go".
   Each band carries two colours: the bright one is the line on the map, the dark
   one is for type, because yellow that reads well as a 6px stroke is unreadable
   as 10px text on white. */
const AADT_BANDS=[[500,'#2e7d32','quiet',4,'#1b5e20'],
                  [1500,'#f0b400','moderate',5.5,'#8a6100'],
                  [Infinity,'#d32f2f','heavy',7,'#b3261e']];
/* Traffic counts are drawn dashed, the route solid. Colour alone doesn't separate
   them — a heavy red count running beside the magenta Erie line reads as one more
   stretch of trail. A dash says "this is a reading laid over the road", not "go this
   way", so the eye never mistakes a busy road for the route. Round caps keep the
   dashes from looking like ticks at the heavier weights. */
const AADT_DASH='7,7';
/* Zoomed out, the quiet streets are not what you are looking for and there is not
   the room to draw them anyway, so the floor rises with the scale — the same idea
   as the milepost interval. Where more is in view than will be drawn the busiest
   survive regardless; this only decides what is worth asking for in the first
   place, which is what keeps a rural county from being drawn as every farm lane. */
const AADT_FLOOR=[[13,0],[12,1000],[11,2500],[10,6000]];
const abs = Math.abs;
const fmtMi = m => m < 10 ? m.toFixed(1) : String(Math.round(m));
// Window bounds are typed by hand and land on round numbers, so they read as
// integers unless a step actually produced a fraction.
const fmtWin = m => abs(m-Math.round(m))<0.05 ? String(Math.round(m)) : m.toFixed(1);
/* A distance answers "how far", a milepost answers "where" — and the milepost is
   the number on the trail sign, in the itinerary column, and in whatever else the
   rider is cross-checking against. Anything that prints a distance prints the mile
   it refers to too. Kept to a tenth throughout, including the rider's own position:
   fmtMi rounds anything over 10 to whole miles, which read as a different scale
   sitting next to the one-decimal mileposts the TOWNS table has always used. */
const fmtMp = m => (m==null || !isFinite(m)) ? '' : m.toFixed(1);
// Intervals a person reads without doing arithmetic — no 3s, no 15s. The cap is a
// backstop on a pathological viewport, not a design limit: at 48px a label the whole
// trail never puts more than a few dozen on screen.
const MILE_LADDER=[1,2,5,10,25,50,100], MILE_CAP=300;
const mpTxt = m => { const s=fmtMp(m); return s ? 'TM '+s : ''; };

/* Facility names/addresses come from a third-party service and land in innerHTML
   and in data-* attributes, so everything interpolated goes through esc() first.
   safeUrl() keeps a hostile record from smuggling a javascript: URL into an href. */
const PREFS='est-prefs-v1';
const PRICES='est-prices-v1';
/* Chain pins carry a wordmark rather than a logo: brand logos are trademarks, and
   shipping them into this repo — or hotlinking them, which the offline story rules
   out anyway — is not ours to do. An abbreviation in the chain's own colour scans
   from the same distance and costs nobody a lawyer. Longest name first, so Hilton
   Garden and Holiday Inn Express aren't eaten by Hilton and Holiday Inn. */
const BRANDS=[
  [/hilton garden/i,'HGI','#00457c'],[/home2/i,'HOME2','#00457c'],[/homewood/i,'HWS','#00457c'],
  [/doubletree/i,'DBLTREE','#00457c'],[/tru by hilton/i,'TRU','#00457c'],[/hampton/i,'HAMPTON','#00457c'],
  [/embassy suites/i,'EMBASSY','#00457c'],[/\bhilton\b/i,'HILTON','#00457c'],
  [/holiday inn express/i,'HIEX','#1f7a3f'],[/holiday inn/i,'HOL INN','#1f7a3f'],
  [/candlewood/i,'CANDLE','#1f7a3f'],[/staybridge/i,'STAYBR','#1f7a3f'],[/crowne plaza/i,'CROWNE','#1f7a3f'],
  [/fairfield/i,'FAIRFLD','#8b1a1a'],[/courtyard/i,'COURTYD','#8b1a1a'],[/residence inn/i,'RESIDNC','#8b1a1a'],
  [/springhill/i,'SPRINGH','#8b1a1a'],[/towneplace/i,'TOWNEPL','#8b1a1a'],[/sheraton/i,'SHERATON','#8b1a1a'],
  [/westin/i,'WESTIN','#8b1a1a'],[/\bmarriott\b/i,'MARRIOTT','#8b1a1a'],
  [/days inn/i,'DAYS','#b8860b'],[/super 8/i,'SUPER 8','#b8860b'],[/ramada/i,'RAMADA','#b8860b'],
  [/howard johnson/i,'HOJO','#b8860b'],[/travelodge/i,'TRVLDG','#b8860b'],[/microtel/i,'MICROTEL','#b8860b'],
  [/baymont/i,'BAYMONT','#b8860b'],[/la quinta/i,'LA QUINTA','#b8860b'],[/\bwyndham\b/i,'WYNDHAM','#b8860b'],
  [/comfort (inn|suites)/i,'COMFORT','#0a5c9e'],[/quality inn/i,'QUALITY','#0a5c9e'],
  [/sleep inn/i,'SLEEP','#0a5c9e'],[/clarion/i,'CLARION','#0a5c9e'],[/econo ?lodge/i,'ECONO','#0a5c9e'],
  [/rodeway/i,'RODEWAY','#0a5c9e'],[/mainstay/i,'MAINSTAY','#0a5c9e'],[/cambria/i,'CAMBRIA','#0a5c9e'],
  [/best western/i,'BEST WN','#123c7b'],[/americinn/i,'AMERICINN','#123c7b'],
  [/motel 6/i,'MOTEL 6','#0d6b3f'],[/extended stay/i,'EXTSTAY','#0d6b3f'],
  [/red roof/i,'RED ROOF','#b3261e']
];
function brandOf(name){
  const n=String(name||'');
  for(let i=0;i<BRANDS.length;i++) if(BRANDS[i][0].test(n)) return {tag:BRANDS[i][1], color:BRANDS[i][2]};
  return null;
}
const fmtMoney = n => (n==null||!isFinite(n)) ? '' : '$'+(Math.round(n)===+n ? n : (+n).toFixed(2));
const ESCMAP={'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'};
const esc = s => String(s==null?'':s).replace(/[&<>"']/g, c=>ESCMAP[c]);
const safeUrl = u => /^https?:\/\//i.test(String(u||'')) ? esc(u) : '';

